CREATE TRIGGER [dbo].[PIMS_MAAINV_I_S_I_TR] ON PIMS_MANAGEMENT_ACTIVITY_INVOICE INSTEAD OF INSERT AS
SET NOCOUNT ON
BEGIN TRY
  IF NOT EXISTS(SELECT * FROM inserted) 
    RETURN;

  
  insert into PIMS_MANAGEMENT_ACTIVITY_INVOICE ("MANAGEMENT_ACTIVITY_INVOICE_ID",
      "MANAGEMENT_ACTIVITY_ID",
      "INVOICE_DT",
